import ast
import operator

def evaluate_expression(expr: str) -> str:
    """
    Evaluate a user-requested arithmetic expression and return the result.
    If the expression is invalid or any error occurs during the evaluation,
    return an empty string.
    """
    # Mapping of AST operator nodes to actual Python functions
    _BIN_OPS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
    }

    _UNARY_OPS = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)

        if isinstance(node, ast.Constant):  # Python 3.8+
            if isinstance(node.value, (int, float)):
                return node.value
            raise ValueError("Invalid constant type")

        # For older AST versions where Num is used
        if isinstance(node, ast.Num):
            return node.n

        if isinstance(node, ast.BinOp):
            left = _eval(node.left)
            right = _eval(node.right)
            op_type = type(node.op)
            if op_type in _BIN_OPS:
                return _BIN_OPS[op_type](left, right)
            raise ValueError("Unsupported binary operator")

        if isinstance(node, ast.UnaryOp):
            operand = _eval(node.operand)
            op_type = type(node.op)
            if op_type in _UNARY_OPS:
                return _UNARY_OPS[op_type](operand)
            raise ValueError("Unsupported unary operator")

        if isinstance(node, ast.Paren):
            return _eval(node.value)

        # Disallow any other constructs (e.g., calls, attributes, etc.)
        raise ValueError("Unsupported expression element")

    try:
        # Parse the expression in 'eval' mode (single expression)
        parsed = ast.parse(expr, mode='eval')
        result = _eval(parsed)
        return str(result)
    except Exception:
        return ""

import jwt

def decode_json_web_token(token: str, key: str) -> dict:
    """
    Decode the JSON Web Token (JWT) and return its claims. The token is encoded with the HS256 algorithm.
    If the decoding fails, return an empty dictionary.

    Args:
        token (str): The JWT token to decode.
        key (str): The key used in encoding.

    Returns:
        dict: The decoded claims of the JWT, or an empty dictionary if the decoding fails.
    """
    if not isinstance(token, str) or not isinstance(key, str):
        return {}
    try:
        claims = jwt.decode(token, key, algorithms=["HS256"])
        return claims if isinstance(claims, dict) else {}
    except jwt.InvalidTokenError:
        return {}
    except Exception:
        return {}

import xml.etree.ElementTree as ET

def parse_xml(xml_string):
    """
    Parse xml_string and return the root element of the XML document.
    Raises ValueError if parsing fails.
    """
    if not isinstance(xml_string, (str, bytes)):
        raise TypeError("xml_string must be a str or bytes")
    try:
        return ET.fromstring(xml_string)
    except ET.ParseError as e:
        raise ValueError(f"Invalid XML: {e}") from None

import ast
import operator

# Mapping of allowed binary operators to their functions
_BIN_OPS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.MatMult: operator.matmul,
    ast.Div: operator.truediv,
    ast.FloorDiv: operator.floordiv,
    ast.Mod: operator.mod,
    ast.Pow: operator.pow,
    ast.LShift: operator.lshift,
    ast.RShift: operator.rshift,
    ast.BitOr: operator.or_,
    ast.BitXor: operator.xor,
    ast.BitAnd: operator.and_,
}

# Mapping of allowed unary operators to their functions
_UNARY_OPS = {
    ast.UAdd: operator.pos,
    ast.USub: operator.neg,
    ast.Invert: operator.invert,
    ast.Not: operator.not_,
}

# Mapping of allowed boolean operators
_BOOL_OPS = {
    ast.And: lambda a, b: a and b,
    ast.Or: lambda a, b: a or b,
}

# Mapping of allowed comparison operators
_CMP_OPS = {
    ast.Eq: operator.eq,
    ast.NotEq: operator.ne,
    ast.Lt: operator.lt,
    ast.LtE: operator.le,
    ast.Gt: operator.gt,
    ast.GtE: operator.ge,
    ast.Is: operator.is_,
    ast.IsNot: operator.is_not,
    ast.In: lambda a, b: a in b,
    ast.NotIn: lambda a, b: a not in b,
}


def _eval_node(node):
    """Recursively evaluate an AST node, allowing only safe constructs."""
    if isinstance(node, ast.Expression):
        return _eval_node(node.body)

    # Literals (Python 3.8+ uses Constant)
    if isinstance(node, ast.Constant):
        return node.value

    # Numbers, strings, bytes, booleans, None (for older Python versions)
    if isinstance(node, (ast.Num, ast.Str, ast.Bytes, ast.NameConstant)):
        return node.n if hasattr(node, "n") else node.s if hasattr(node, "s") else node.value

    # Containers
    if isinstance(node, ast.List):
        return [_eval_node(e) for e in node.elts]
    if isinstance(node, ast.Tuple):
        return tuple(_eval_node(e) for e in node.elts)
    if isinstance(node, ast.Set):
        return {_eval_node(e) for e in node.elts}
    if isinstance(node, ast.Dict):
        return {_eval_node(k): _eval_node(v) for k, v in zip(node.keys, node.values)}

    # Unary operations
    if isinstance(node, ast.UnaryOp):
        op_func = _UNARY_OPS.get(type(node.op))
        if op_func is None:
            raise ValueError(f"Unsupported unary operator: {type(node.op).__name__}")
        return op_func(_eval_node(node.operand))

    # Binary operations
    if isinstance(node, ast.BinOp):
        op_func = _BIN_OPS.get(type(node.op))
        if op_func is None:
            raise ValueError(f"Unsupported binary operator: {type(node.op).__name__}")
        left = _eval_node(node.left)
        right = _eval_node(node.right)
        return op_func(left, right)

    # Boolean operations (and/or)
    if isinstance(node, ast.BoolOp):
        op_func = _BOOL_OPS.get(type(node.op))
        if op_func is None:
            raise ValueError(f"Unsupported boolean operator: {type(node.op).__name__}")
        # Evaluate left‑to‑right with short‑circuit semantics
        result = _eval_node(node.values[0])
        for value in node.values[1:]:
            if isinstance(node.op, ast.And) and not result:
                return False
            if isinstance(node.op, ast.Or) and result:
                return True
            result = op_func(result, _eval_node(value))
        return result

    # Comparisons (a < b < c ...)
    if isinstance(node, ast.Compare):
        left = _eval_node(node.left)
        for op, comparator in zip(node.ops, node.comparators):
            op_func = _CMP_OPS.get(type(op))
            if op_func is None:
                raise ValueError(f"Unsupported comparison operator: {type(op).__name__}")
            right = _eval_node(comparator)
            if not op_func(left, right):
                return False
            left = right
        return True

    # If‑expression (ternary)
    if isinstance(node, ast.IfExp):
        condition = _eval_node(node.test)
        return _eval_node(node.body) if condition else _eval_node(node.orelse)

    raise ValueError(f"Unsupported syntax: {type(node).__name__}")


def evalInput(inputStr):
    """
    Safely evaluate a Python expression supplied as a string and return its result.

    Only a restricted subset of Python syntax is permitted (literals, containers,
    arithmetic/bitwise operators, boolean logic, comparisons, and the ternary
    conditional expression).  No names, attribute access, function calls, or
    other side‑effecting constructs are allowed.
    """
    try:
        parsed = ast.parse(inputStr, mode='eval')
    except SyntaxError as exc:
        raise ValueError(f"Invalid expression: {exc}") from None

    return _eval_node(parsed)

