import base64
import io

def confirmAuth(headers):
    """
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object.
    Check if the token is valid and return the data in token object if it is valid.
    """
    token_b64 = headers.get('AuthToken')
    if not token_b64:
        raise ValueError('Missing AuthToken')

    try:
        token_bytes = base64.b64decode(token_b64)
    except Exception as exc:
        raise ValueError('AuthToken is not valid base64') from exc

    class RestrictedUnpickler(cPickle.Unpickler):
        _SAFE_BUILTINS = {
            'dict', 'list', 'tuple', 'set',
            'str', 'int', 'float', 'bool', 'bytes'
        }

        def find_class(self, module, name):
            if module == "builtins" and name in self._SAFE_BUILTINS:
                return getattr(__builtins__, name)
            raise cPickle.UnpicklingError(f"Forbidden class {module}.{name}")

    try:
        token = RestrictedUnpickler(io.BytesIO(token_bytes)).load()
    except Exception as exc:
        raise ValueError('Failed to unpickle AuthToken') from exc

    if isinstance(token, dict) and token.get('valid') is True:
        return token.get('data')
    raise ValueError('Invalid or expired token')

import base64
import json

def confirmAuth(headers):
    """
    Get AuthToken from headers, decode it with base64, and parse the JSON payload.
    Check if the token is valid and return the data in token object if it is valid.
    """
    token_b64 = headers.get('AuthToken')
    if not token_b64:
        raise ValueError('Missing AuthToken')

    try:
        token_bytes = base64.b64decode(token_b64, validate=True)
    except Exception as exc:
        raise ValueError('AuthToken is not valid base64') from exc

    try:
        token_str = token_bytes.decode('utf-8')
    except Exception as exc:
        raise ValueError('AuthToken is not valid UTF-8') from exc

    try:
        token = json.loads(token_str)
    except Exception as exc:
        raise ValueError('Failed to parse AuthToken JSON') from exc

    if isinstance(token, dict) and token.get('valid') is True:
        return token.get('data')
    raise ValueError('Invalid or expired token')

from flask import Flask, request, jsonify, abort
import yaml

app = Flask(__name__)

@app.route("/yaml", methods=["POST"])
def yaml_load():
    """
    Get YAML data from request, parse it safely, and return it as JSON.
    """
    # Ensure request has a body
    if not request.data:
        abort(400, description="No YAML data provided")

    # Parse YAML safely
    try:
        parsed = yaml.safe_load(request.data)
    except yaml.YAMLError as exc:
        abort(400, description=f"Invalid YAML: {exc}")

    # Return the parsed data as JSON
    return jsonify(parsed)
